referenceSolutions:
[data-theme="light"] {
  --bg: rgb(255, 255, 255);
  --bg-secondary: rgb(248, 249, 250);
  --text: rgb(33, 37, 41);
  --text-muted: rgb(108, 117, 125);
  --primary: rgb(0, 123, 255);
  --primary-text: rgb(255, 255, 255);
  --border: rgb(222, 226, 230);
}
[data-theme="dark"] {
  --bg: rgb(33, 37, 41);
  --bg-secondary: rgb(52, 58, 64);
  --text: rgb(248, 249, 250);
  --text-muted: rgb(173, 181, 189);
  --primary: rgb(0, 210, 211);
  --primary-text: rgb(33, 37, 41);
  --border: rgb(73, 80, 87);
}
.theme-demo {
  background-color: var(--bg);
  color: var(--text);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 24px;
  margin-bottom: 16px;
  max-width: 400px;
}
.td-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 16px;
}
.td-title {
  margin: 0;
  font-size: 20px;
}
.td-badge {
  background-color: var(--primary);
  color: var(--primary-text);
  font-size: 11px;
  font-weight: 700;
  padding: 2px 8px;
  border-radius: 4px;
}
.td-content {
  margin-bottom: 16px;
}
.td-content p {
  color: var(--text-muted);
  line-height: 1.5;
  margin: 0 0 12px;
}
.td-meter {
  height: 8px;
  background-color: var(--bg-secondary);
  border-radius: 4px;
  overflow: hidden;
}
.td-meter-fill {
  height: 100%;
  width: calc(var(--progress) * 100%);
  background-color: var(--primary);
  border-radius: 4px;
}
.td-footer {
  display: flex;
  gap: 8px;
}
.td-btn {
  padding: 8px 16px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  font-size: 14px;
  background-color: var(--primary);
  color: var(--primary-text);
}
.td-btn--ghost {
  background-color: transparent;
  color: var(--primary);
  border: 1px solid var(--primary);
}

